import{_ as e,o as a,c as s,ay as l,aH as i,aI as r,aJ as c,aK as d,aL as n,aM as o,aN as p,aO as m,aP as h,aQ as g,aR as y,aS as _}from"./chunks/framework.wZ8OcQt2.js";const D=JSON.parse('{"title":"签到类型","description":"","frontmatter":{},"headers":[],"relativePath":"guide/type.md","filePath":"guide/type.md","lastUpdated":1778198632000}'),b={name:"guide/type.md"};function x(u,t,k,v,w,f){return a(),s("div",null,[...t[0]||(t[0]=[l('<h1 id="签到类型" tabindex="-1">签到类型 <a class="header-anchor" href="#签到类型" aria-label="Permalink to “签到类型”">​</a></h1><h2 id="课程、班级、群聊的区别" tabindex="-1">课程、班级、群聊的区别 <a class="header-anchor" href="#课程、班级、群聊的区别" aria-label="Permalink to “课程、班级、群聊的区别”">​</a></h2><p>打开学习通 App 的聊天页，课程是绿色图标，班级是黄色图标，群聊是学生头像拼接。</p><img src="'+i+'" style="width:min(60vw, 300px);"><details class="details custom-block"><summary>怎么签？</summary><p><strong>1. 课程签到、班级签到</strong></p><p>直接在【课程学习】独自完成除二维码以外的签到类型，二维码需要同学去教室扫。班级签到本质是隐藏了课程入口的课程签到。</p><p><strong>2. 群聊签到</strong></p><p>在【实时学习】中监听签到通知，可独自完成各种类型的签到。</p></details><h2 id="课程签到的类型" tabindex="-1">课程签到的类型 <a class="header-anchor" href="#课程签到的类型" aria-label="Permalink to “课程签到的类型”">​</a></h2><p><img src="'+r+'" alt="签到类型辨别"></p><h4 id="_1-二维码签到" tabindex="-1">1. 二维码签到 <a class="header-anchor" href="#_1-二维码签到" aria-label="Permalink to “1. 二维码签到”">​</a></h4><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">提示</p><p>过期二维码漏洞已在 2023年4月8号 被学习通官方修复！ 截至到目前，二维码签到修复已经快两三年了，依旧没人能实现破解过期二维码签到，更别提免码直签了。 所谓的免码直签不过是 “群聊签到” 里的旧版二维码签到，几乎没有老师使用。</p></div><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">提示</p><p>二维码解码后是个链接，例如：<a href="https://mobilelearn.chaoxing.com/widget/sign/e?id=80001231452&amp;enc=FACDD34DBC291EE176" target="_blank" rel="noreferrer">https://mobilelearn.chaoxing.com/widget/sign/e?id=80001231452&amp;enc=FACDD34DBC291EE176</a> 包含 id 和 enc 参数，enc 每 10 秒无规律变化一次。目前无人发现规律！</p></div><details class="details custom-block"><summary>怎么签？</summary><p>点击 <strong>扫码学习</strong> 就可以扫码签到了，如果教师设置了位置限制，可以地图选点签到。</p><p>已自动绕过 “同一设备不能重复签到” 的限制。</p><p>PS：点击 “请人帮忙” 可以快捷把账号密码分享给同学帮你签哦~</p></details><h4 id="_2-位置签到" tabindex="-1">2. 位置签到 <a class="header-anchor" href="#_2-位置签到" aria-label="Permalink to “2. 位置签到”">​</a></h4><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">提示</p><p>使用该方式会触发 “使用作弊工具” 提示吗？</p><p>答：不会。开发者早已注意到这种情况，已有应对策略，教师端仅显示正常签到记录。</p></div><details class="details custom-block"><summary>怎么签？</summary><p>地图选点，可以自行修改签到位置的文本。会员用户可获取教师设置的位置。</p><p>只要坐标对了，你填 “学园都市” 都能签上。</p></details><h4 id="_3-手势签到-签到码签到" tabindex="-1">3. 手势签到 / 签到码签到 <a class="header-anchor" href="#_3-手势签到-签到码签到" aria-label="Permalink to “3. 手势签到 / 签到码签到”">​</a></h4><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">提示</p><p>签到码是 4-8 位的数字，不是二维码！</p></div><details class="details custom-block"><summary>怎么签？</summary><p>点自动获取，就能获取到签到码、手势图，然后点立即签到。</p></details><h4 id="_4-图片签到" tabindex="-1">4. 图片签到 <a class="header-anchor" href="#_4-图片签到" aria-label="Permalink to “4. 图片签到”">​</a></h4><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">提示</p><p>会员用户可一键借用同学照片签到</p></div><details class="details custom-block"><summary>怎么签？</summary><p>用户可上传任意图片进行签到。</p><p>不上传图片的话，也会签到成功，但是图片缺失。</p></details><h2 id="签到的结果" tabindex="-1">签到的结果 <a class="header-anchor" href="#签到的结果" aria-label="Permalink to “签到的结果”">​</a></h2><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">警告</p><p>部分同学分不清【1.未签】和【2.缺勤】，缺勤是你老师手动设置的！</p></div><table tabindex="0"><thead><tr><th style="text-align:center;">1. 未签</th><th style="text-align:center;">2. 缺勤</th><th style="text-align:center;">3. 教师代签</th><th style="text-align:center;">4. 虚拟定位</th><th style="text-align:center;">5. 已签</th></tr></thead><tbody><tr><td style="text-align:center;">如果没签到，显示的是这个</td><td style="text-align:center;">教师手动设置的</td><td style="text-align:center;"></td><td style="text-align:center;">v3 小程序支持自动绕过</td><td style="text-align:center;"></td></tr><tr><td style="text-align:center;"><img src="'+c+'" style="width:min(15vw, 160px);"></td><td style="text-align:center;"><img src="'+d+'" style="width:min(15vw, 160px);"></td><td style="text-align:center;"><img src="'+n+'" style="width:min(15vw, 160px);"></td><td style="text-align:center;"><img src="'+o+'" style="width:min(15vw, 160px);"></td><td style="text-align:center;"><img src="'+p+'" style="width:min(15vw, 160px);"></td></tr></tbody></table><table tabindex="0"><thead><tr><th style="text-align:center;">6. 事假</th><th style="text-align:center;">7. 病假</th><th style="text-align:center;">8. 公假</th><th style="text-align:center;">9. 迟到</th><th style="text-align:center;">10. 早退</th></tr></thead><tbody><tr><td style="text-align:center;"><img src="'+m+'" style="width:min(15vw, 160px);"></td><td style="text-align:center;"><img src="'+h+'" style="width:min(15vw, 160px);"></td><td style="text-align:center;"><img src="'+g+'" style="width:min(15vw, 160px);"></td><td style="text-align:center;"><img src="'+y+'" style="width:min(15vw, 160px);"></td><td style="text-align:center;"><img src="'+_+'" style="width:min(15vw, 160px);"></td></tr></tbody></table>',24)])])}const S=e(b,[["render",x]]);export{D as __pageData,S as default};
